class Solution {
    public int[] shortestAlternatingPaths(int n, int[][] redEdges, int[][] blueEdges) {
        List<List<Integer>>[] graph = new List[2];
        graph[0] = new ArrayList<>();
        graph[1] = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph[0].add(new ArrayList<>());
            graph[1].add(new ArrayList<>());
        }
        for (int[] e : redEdges) graph[0].get(e[0]).add(e[1]);
        for (int[] e : blueEdges) graph[1].get(e[0]).add(e[1]);

        int[][] dist = new int[2][n];
        Arrays.fill(dist[0], -1);
        Arrays.fill(dist[1], -1);
        dist[0][0] = 0;
        dist[1][0] = 0;

        Queue<int[]> q = new LinkedList<>();
        q.offer(new int[]{0, 0});
        q.offer(new int[]{0, 1});

        while (!q.isEmpty()) {
            int[] cur = q.poll();
            int node = cur[0], color = cur[1];
            int nextColor = 1 - color;
            for (int neighbor : graph[nextColor].get(node)) {
                if (dist[nextColor][neighbor] == -1) {
                    dist[nextColor][neighbor] = dist[color][node] + 1;
                    q.offer(new int[]{neighbor, nextColor});
                }
            }
        }

        int[] ans = new int[n];
        for (int i = 0; i < n; i++) {
            int min = -1;
            if (dist[0][i] != -1 && dist[1][i] != -1) min = Math.min(dist[0][i], dist[1][i]);
            else if (dist[0][i] != -1) min = dist[0][i];
            else if (dist[1][i] != -1) min = dist[1][i];
            ans[i] = min;
        }
        return ans;
    }
}
